params.seo_schema_markup:
{
    "@context": "https://schema.org",
    "@type": "LocalBusiness",
    "name": "{COMPANY} - {SERVICE} in {CITY}",
    "description": "Professional {SERVICE} in {CITY} by {COMPANY}. Expert Team Affordable Rates. Call {PHONE} for free quote!",
    "url": "https://razzaqengineering.com/{CITY}/{SERVICE}",
    "telephone": "{PHONE}",
    "image": "https://razzaqengineering.com/images/services/{SERVICE}.jpg",
    "priceRange": "Rs. 5,000 - 50,000",
    "address": {
        "@type": "PostalAddress",
        "addressLocality": "{CITY}",
        "addressCountry": "PK"
    },
    "areaServed": {
        "@type": "City",
        "name": "{CITY}",
        "description": "Serving {AREAS} in {CITY}"
    },
    "makesOffer": {
        "@type": "Offer",
        "itemOffered": {
            "@type": "Service",
            "name": "{SERVICE}",
            "description": "Professional {SERVICE} services in {CITY}",
            "areaServed": {
                "@type": "City",
                "name": "{CITY}"
            }
        }
    },
    "openingHoursSpecification": {
        "@type": "OpeningHoursSpecification",
        "dayOfWeek": ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"],
        "opens": "09:00",
        "closes": "18:00"
    }
}
